import React, { useState, useEffect } from 'react';
import {
  Container, Grid, Card, CardMedia, CardContent,
  Typography, Button, TextField, Box, Chip, FormControl, InputLabel, Select, MenuItem
} from '@mui/material';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const categories = [
  { value: 'books', label: '📚 كتب' },
  { value: 'notes', label: '📝 ملازم' },
  { value: 'tools', label: '🔧 أدوات' },
  { value: 'electronics', label: '💻 إلكترونيات' },
  { value: 'other', label: '📦 أخرى' }
];

const types = [
  { value: '', label: 'الكل' },
  { value: 'sell', label: '💰 للبيع' },
  { value: 'borrow', label: '🔄 للإعارة' },
  { value: 'donate', label: '🎁 مجاني' }
];

export default function Home() {
  const navigate = useNavigate();
  const [products, setProducts] = useState([]);
  const [search, setSearch] = useState('');
  const [category, setCategory] = useState('');
  const [type, setType] = useState('');

  useEffect(() => {
    fetchProducts();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [search, category, type]);

  const fetchProducts = async () => {
    const params = new URLSearchParams();
    if (search) params.append('search', search);
    if (category) params.append('category', category);
    if (type) params.append('type', type);

    const res = await axios.get(`http://localhost:5000/api/products?${params}`);
    setProducts(res.data);
  };

  const getTypeLabel = (type) => {
    switch(type) {
      case 'sell': return '💰 للبيع';
      case 'borrow': return '🔄 للإعارة';
      case 'donate': return '🎁 مجاني';
      default: return '';
    }
  };

  const getTypeColor = (type) => {
    switch(type) {
      case 'sell': return 'primary';
      case 'borrow': return 'secondary';
      case 'donate': return 'success';
      default: return 'default';
    }
  };

  return (
    <Container sx={{ py: 4 }}>
      <Box sx={{ textAlign: 'center', mb: 4 }}>
        <Typography variant="h2" color="primary" sx={{ fontWeight: 'bold', mb: 1 }}>

        </Typography>
        <Typography variant="h5" color="text.secondary">
        مـن الطـالـب إلى الطـالـب
        </Typography>
      </Box>

      {/* البحث والتصفية */}
      <Box sx={{ display: 'flex', gap: 2, mb: 4, flexWrap: 'wrap' }}>
        <TextField
          label="🔍 ابحث عن منتج..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          sx={{ flex: 1, minWidth: 200 }}
        />
        <FormControl sx={{ minWidth: 120 }}>
          <InputLabel>النوع</InputLabel>
          <Select value={type} label="النوع" onChange={(e) => setType(e.target.value)}>
            {types.map(t => (
              <MenuItem key={t.value} value={t.value}>{t.label}</MenuItem>
            ))}
          </Select>
        </FormControl>
        <Box sx={{ display: 'flex', gap: 1 }}>
          {categories.map(cat => (
            <Chip
              key={cat.value}
              label={cat.label}
              onClick={() => setCategory(category === cat.value ? '' : cat.value)}
              color={category === cat.value ? 'primary' : 'default'}
              clickable
            />
          ))}
        </Box>
      </Box>

      {/* شبكة المنتجات */}
      <Grid container spacing={3}>
        {products.map(product => (
          <Grid item xs={12} sm={6} md={4} key={product._id}>
            <Card sx={{ height: '100%', display: 'flex', flexDirection: 'column', cursor: 'pointer' }} onClick={() => navigate(`/product/${product._id}`)}>
              <CardMedia
                component="img"
                height="200"
                image={product.images[0] ? `http://localhost:5000${product.images[0]}` : 'https://via.placeholder.com/300x200?text=No+Image'}
                alt={product.title}
              />
              <CardContent sx={{ flexGrow: 1 }}>
                <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                  <Chip label={getTypeLabel(product.type)} color={getTypeColor(product.type)} size="small" />
                  <Chip label={categories.find(c => c.value === product.category)?.label} variant="outlined" size="small" />
                </Box>
                <Typography variant="h6" noWrap>{product.title}</Typography>
                <Typography color="text.secondary" sx={{ mb: 1 }}>
                  {product.condition === 'new' ? '✨ جديد' : product.condition === 'like-new' ? '🔄 شبه جديد' : '📦 مستعمل'}
                </Typography>
                <Typography variant="h5" color="primary" sx={{ fontWeight: 'bold' }}>
                  {product.type === 'donate' ? 'مجاني 🎁' : product.type === 'borrow' ? 'للإعارة 🔄' : `${product.price} ر.س`}
                </Typography>
                <Typography variant="body2" sx={{ mt: 1 }}>
                  👤 {product.seller?.name}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>

      {products.length === 0 && (
        <Typography variant="h6" color="text.secondary" align="center" sx={{ mt: 4 }}>
          لا توجد منتجات متاحة حالياً 📝
        </Typography>
      )}
    </Container>
  );
}
